// WEEK HELPERS
function gw(o){const n=new Date(),m=new Date(n);m.setDate(n.getDate()-dw()+o*7);const DN=['Pzt','Sal','Çar','Per','Cum','Cmt','Paz'];
return Array.from({length:7},(_,i)=>{const d=new Date(m);d.setDate(m.getDate()+i);return{s:DN[i],dt:d.toISOString().slice(0,10),dy:d.getDate(),mo:d.getMonth()+1,td:d.toISOString().slice(0,10)===tISO(),we:i>=5}})}
function chk(r){if(!r||!r.ig)return true;return r.ig.every(i=>{const nm=i.split(':')[0].trim().toLowerCase();return S.F.some(f=>f.n.toLowerCase()===nm&&f.cr>0)||S.P.some(p=>p.n.toLowerCase()===nm&&p.cr>0)||(S.DON&&S.DON.some(d=>d.n.toLowerCase()===nm&&d.cr>0))})}

