const mkList=(S.SE.mk||['BİM','Migros','A101']).join(',');e.innerHTML='<div class="md" onclick="event.stopPropagation()" style="padding:16px"><div style="font-size:28px;text-align:center;margin-bottom:6px">🛍️</div><h3 style="text-align:center;margin-bottom:6px">Alındı!</h3><p style="font-size:11px;color:var(--txtL);text-align:center;margin-bottom:12px"><strong>'+esc(item.nm)+'</strong></p><div style="margin-bottom:10px"><label style="font-size:11px;color:var(--txtL);font-weight:700">Miktar</label><input id="tsh_qt" value="'+esc(item.qt)+'" style="width:100%;margin-top:4px;text-align:center;font-size:14px;font-weight:700"></div><div style="display:flex;gap:6px;margin-bottom:10px"><div style="flex:1"><label style="font-size:11px;color:var(--txtL);font-weight:700">Fiyat (₺)</label><input id="tsh_pr" type="number" value="'+(item.pr||'')+'" placeholder="0.00" style="width:100%;margin-top:4px;text-align:center;font-size:14px;font-weight:700"></div><div style="flex:1"><label style="font-size:11px;color:var(--txtL);font-weight:700">Nereye?</label><select id="tsh_loc" style="width:100%;margin-top:4px;padding:9px 6px;font-size:12px"><option value="">'+(item.loc==='buz'?'':'')+'Kaydetme</option><option value="buz"'+(item.loc==='buz'?' selected':'')+'>🧊 Buzdolabı</option><option value="kil"'+(item.loc==='kil'?' selected':'')+'>🧹 Kiler</option></select></div></div><div style="margin-bottom:14px"><label style="font-size:11px;color:var(--txtL);font-weight:700">Market</label><input id="tsh_mk" list="tsh_mklist" value="'+(item.mk||'')+'" placeholder="Market adı..." style="width:100%;margin-top:4px"><datalist id="tsh_mklist">'+(S.SE.mk||['BİM','Migros','A101']).map(m=>'<option value="'+esc(m)+'">').join('')+'</datalist></div><div style="display:flex;gap:8px"><button class="btn bg" onclick="document.querySelector(\'.mo\').remove()" style="flex:1">İptal</button><button class="btn bm" onclick="(()=>{const qt=document.getElementById(\'tsh_qt\').value;const mk=document.getElementById(\'tsh_mk\').value;const pr=parseFloat(document.getElementById(\'tsh_pr\').value)||0;const loc=document.getElementById(\'tsh_loc\').value;document.querySelector(\'.mo\').remove();tshMk('+id+',mk,qt,pr,loc)})()" style="flex:1">✅ Tamam</button></div></div>';
