function tshMk(id,mk,qt,pr,loc){const item=S.SH.find(i=>i.id===id);if(!item)return;
item.dn=true;if(mk)item.mk=mk;if(qt)item.qt=qt;if(pr>0)item.pr=pr;if(loc)item.loc=loc;
// Fiyat → Finans
if(pr>0){
  if(!S.GIDER)S.GIDER=[];
  S.GIDER.push({id:Date.now(),dt:tISO().slice(0,10),amt:pr,cat:'Mutfak Alışveriş',mod:'MUTFAK',desc:(mk?mk+' · ':'')+item.nm,usr:S.user||'Görkem'});
  sv('GIDER');
}
// Stok güncelle
const num=parseFloat((item.qt||'').match(/[\d.]+/)?.[0])||0;
if(!S.PH)S.PH={};if(item.pr>0)S.PH[item.nm.toLowerCase()]=item.pr;
const curLoc=loc||item.loc||'';
if(curLoc==='buz'){
  const fi=S.F.find(f=>f.n.toLowerCase()===item.nm.toLowerCase());
  if(fi){fi.cr=Math.round((fi.cr+(num||1))*10)/10;fi.bt=tISO();sv('F');}
  else{S.F.push({n:item.nm,u:'adet',mn:1,cr:num||1,ic:'📦',ct:'Diğer',br:'',mk:mk||'BİM'});sv('F');}
  toast('🧊 '+item.nm+' buzdolabına kaydedildi','succ');
}else if(curLoc==='kil'){
  const pi=S.P.find(p=>p.n.toLowerCase()===item.nm.toLowerCase());
  if(pi){pi.cr=Math.round((pi.cr+(num||1))*10)/10;pi.bt=tISO();sv('P');}
  else{S.P.push({n:item.nm,u:'adet',mn:1,cr:num||1,ic:'📦',ct:'Diğer',br:'',mk:mk||'BİM'});sv('P');}
  toast('🧹 '+item.nm+' kilere kaydedildi','succ');
}else{
  const fi=S.F.find(f=>f.n.toLowerCase()===item.nm.toLowerCase());
  if(fi){if(num>0)fi.cr=Math.round((fi.cr+num)*10)/10;else fi.cr=Math.max(fi.cr,fi.mn||1);fi.bt=tISO();sv('F');}
}
sv('SH');rn()}
