function svBitenler(keys){
const mo=document.querySelector('.mo');
if(!S.TK)S.TK={};
let cnt=0;
keys.forEach((combo,i)=>{
const sepIdx=combo.indexOf(':');
const key=combo.slice(0,sepIdx),nm=combo.slice(sepIdx+1);
const cb=document.getElementById('bit_'+i);
if(!cb||!cb.checked)return;
const qInp=document.getElementById('bitq_'+i);
const qty=qInp?Math.max(0,Number(qInp.value)||1):1;
const item=(key==='F'?S.F:key==='DON'?S.DON:S.P).find(x=>x.n===nm);
if(!item)return;
// Stoktan düş (sıfırlama değil — kullanıcının söylediği kadar)
const newCr=Math.max(0,Math.round((item.cr-qty)*10)/10);
const actualUsed=item.cr-newCr;// gerçek düşülen miktar
item.cr=newCr;
// B5: tüketim kaydı — stok sıfırlandıysa süreyi kaydet
if(newCr===0&&item.bt){
const days=Math.max(1,Math.floor((Date.now()-new Date(item.bt))/(864e5)));
if(!S.TK[nm])S.TK[nm]={history:[],avg:0};
S.TK[nm].history.push(days);
if(S.TK[nm].history.length>10)S.TK[nm].history=S.TK[nm].history.slice(-10);
S.TK[nm].avg=Math.round(S.TK[nm].history.reduce((a,b)=>a+b,0)/S.TK[nm].history.length);
item.avgDays=S.TK[nm].avg;item.ft=tISO();}
// Alışverişe ekle (mevcut yoksa)
if(!S.SH.some(s=>s.nm.toLowerCase()===nm.toLowerCase()&&!s.dn)){
const neededQty=item.mn>0?item.mn:qty;
const qt=neededQty+' '+item.u;
S.SH.push({id:Date.now()+Math.random(),nm,qt,mk:item.mk||'BİM',br:item.br||'',pr:0,dn:false,ab:'BİTTİ'});
cnt++;}
});
sv('F');sv('P');sv('DON');sv('SH');sv('TK');
if(mo)mo.remove();
toast(cnt>0?'🛒 '+cnt+' ürün alışverişe eklendi!':'Seçili ürün yok.',cnt>0?'succ':'info');
rn();}
function us(k,n,f,v){const item=S[k].find(x=>x.n===n);if(item){item[f]=v;sv(k);rn()}}
function ds(k,n){
const usedIn=S.R.filter(r=>r.ig&&r.ig.some(i=>i.split(':')[0].trim().toLowerCase()===n.toLowerCase()));
if(usedIn.length>0){
if(!confirm('"'+n+'" şu tariflerde kullanılıyor:\n'+usedIn.map(r=>r.e+' '+r.n).join('\n')+'\n\nYine de silmek istiyor musun?'))return}
else if(!confirm('"'+n+'" silinecek. Emin misin?'))return;
S[k]=S[k].filter(x=>x.n!==n);sv(k);rn()}
