function soe(k,on){const f=S[k].find(x=>x.n===on);if(!f)return;f.n=$('oe_n').value||f.n;f.u=$('oe_u').value;f.ct=$('oe_ct').value||f.ct;f.cr=Number($('oe_cr').value);f.mn=Number($('oe_mn').value);f.br=$('oe_br').value;f.mk=$('oe_mk').value;f.ic=$('oe_ic').value||f.ic;f.pk=$('oe_pk')?$('oe_pk').value:f.pk;sv(k);document.querySelector('.mo').remove();rn()}

