// POST-IT — FAZ 9 (#26 7 gün soluklaşma + sil? uyarısı)
function postH(){
const now=new Date();
function piCol(u){return u==='Görkem'?'#BAE1FF':u==='Esra'?'#F4C0D1':'#FFFACD'}
return'<h2>💬 Buzdolabı Sohbet</h2><div class="cd" style="display:flex;gap:8px"><input id="pi" placeholder="Not yaz..." style="flex:1"><button class="btn bm" style="width:auto" onclick="api()">📌</button></div><div style="display:flex;flex-wrap:wrap;gap:10px;justify-content:center;padding:14px;min-height:180px;background:var(--card);border-radius:var(--r);border:1px solid var(--brd)">'+(S.PI.length===0?'<p style="color:var(--txtL);font-size:12px">Buzdolabı boş, bir not bırak!</p>':S.PI.map((p,i)=>{const bg=piCol(p.w);const age=p.d?Math.floor((now-new Date(p.d))/(864e5)):0;const faded=age>=7;const read=p.r||false;
// FAZ 9 — #26: Eski not → tıkla sil?
const fadedClick=faded?'onclick="if(confirm(\'Bu not '+age+' gün önce yazıldı. Silmek ister misin?\')){'+'S.PI.splice('+i+',1);sv(\'PI\');rn()}"':'';
return'<div class="postit" style="background:'+bg+';--rot:'+(((i*37)%12)-6)+'deg;opacity:'+(faded?0.38:read?0.7:1)+';'+(faded?'cursor:pointer;border:1px dashed #E74C3C':'')+'" '+fadedClick+'><div style="font-size:9px;font-weight:800;color:'+(p.w==='Görkem'?'#1B4965':'#9B59B6')+';margin-bottom:3px">'+(p.w==='Görkem'?'👨':'👩')+' '+esc(p.w)+(faded?'<span style="background:#E74C3C;color:#fff;font-size:7px;padding:1px 5px;border-radius:4px;margin-left:4px">'+age+'g · sil?</span>':'')+'</div>'+esc(p.t)+(p.w!==S.user&&!read&&!faded?'<div style="margin-top:5px"><span style="font-size:8px;background:#9B59B6;color:#fff;padding:2px 6px;border-radius:4px;cursor:pointer" onclick="event.stopPropagation();S.PI['+i+'].r=true;sv(\'PI\');rn()">✓ Okudum</span></div>':'')+(read&&!faded?'<div style="font-size:7px;color:#27AE60;margin-top:2px">✓ okundu</div>':'')+'<div style="font-size:7px;opacity:.5;position:absolute;bottom:4px;right:6px">'+(p.d||'')+'</div>'+(faded?''/*no X button on faded, tap to delete*/:'<div style="position:absolute;top:3px;right:5px;font-size:9px;cursor:pointer;opacity:.4" onclick="S.PI.splice('+i+',1);sv(\'PI\');rn()">✕</div>')+'</div>'}).join(''))+'</div>'+
(S.PI.some(p=>p.d&&Math.floor((now-new Date(p.d))/(864e5))>=7)?'<button class="btn bd" style="margin-top:8px;font-size:11px" onclick="S.PI=S.PI.filter(p=>!p.d||(Math.floor((new Date()-new Date(p.d))/(864e5))<7));sv(\'PI\');rn()">🗑 Eski notları temizle</button>':'')
}
function api(){const t=$('pi').value;if(!t)return;S.PI.unshift({t,w:S.user,d:tISO(),r:false});if(S.PI.length>10)S.PI=S.PI.slice(0,10);sv('PI');rn()}

