// Ekmek tazeliği: gün farkına göre durum
function ekTazelik(dt,raf){
  if(!dt)return{renk:'var(--brd)',yazı:'var(--txtL)',etiket:'?',pct:0,icon:'❓'};
  const gun=Math.floor((Date.now()-new Date(dt))/864e5);
  const kalan=Math.max(0,raf-gun);
  const pct=Math.max(0,Math.min(100,Math.round(kalan/raf*100)));
  if(kalan<=0)return{renk:'var(--danger)',yazı:'#791F1F',etiket:'Bayat!',pct:0,icon:'🔴'};
  if(kalan===1)return{renk:'var(--warn)',yazı:'#7D6608',etiket:'Son gün',pct,icon:'🟡'};
  if(pct>=60)return{renk:'var(--succ)',yazı:'#085041',etiket:kalan+' gün',pct,icon:'🟢'};
  return{renk:'var(--warn)',yazı:'#7D6608',etiket:kalan+' gün',pct,icon:'🟡'};
}

function ekmekH(){
  const liste=S.EK||[];
  const taze=liste.filter(e=>{const t=ekTazelik(e.dt,e.raf);return t.pct>0});
  const bayat=liste.filter(e=>{const t=ekTazelik(e.dt,e.raf);return t.pct<=0});
  const toplamAdet=taze.reduce((a,e)=>a+(e.adet||1),0);
  
  // Toplam taze ekmek durumu
  const durum=toplamAdet===0?{bg:'var(--dangerL)',cl:'var(--danger)',ikon:'😱',metin:'Ekmek bitti!'}:
               toplamAdet===1?{bg:'var(--warnL)', cl:'var(--warn)', ikon:'😬',metin:'Son ekmek'}:
                              {bg:'var(--sL)',    cl:'var(--sec)',  ikon:'🍞', metin:toplamAdet+' ekmek mevcut'};

  return'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">'+
    '<h2 style="margin:0">🍞 Ekmeklik</h2>'+
    '<button class="btn bm" style="width:auto;padding:8px 14px;font-size:11px" onclick="ekEkleModal()">+ Ekle</button>'+
  '</div>'+
  // ── Durum kartı ──
  '<div style="background:'+durum.bg+';border-radius:var(--r);padding:14px;margin-bottom:12px;display:flex;align-items:center;gap:12px">'+
    '<div style="font-size:40px">'+durum.ikon+'</div>'+
    '<div style="flex:1">'+
      '<div style="font-size:16px;font-weight:800;color:'+durum.cl+'">'+durum.metin+'</div>'+
      (toplamAdet===0?
        '<button class="btn bm" style="width:auto;padding:6px 14px;font-size:11px;margin-top:8px" onclick="ekAlisEkle()">🛒 Alışverişe Ekle</button>':
        '<div style="font-size:11px;color:var(--txtL);margin-top:3px">'+taze.map(e=>e.ic+' '+e.tip+(e.adet>1?' ('+e.adet+')':'')).join(' · ')+'</div>'+
        '<button class="btn bm" style="width:auto;padding:6px 14px;font-size:11px;margin-top:8px" onclick="ekAlisEkle()">🛒 Alışverişe Ekle</button>'
      )+
    '</div>'+
  '</div>'+
  // ── Hızlı ekle butonları ──
  '<div class="cd" style="padding:12px;margin-bottom:12px">'+
    '<div style="font-size:10px;font-weight:800;color:var(--txtL);text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px">⚡ Hızlı Ekle</div>'+
    '<div style="display:flex;gap:6px;flex-wrap:wrap">'+
    EKMEK_TIPLER.slice(0,8).map(t=>
      '<button onclick="ekHizliEkle(\''+t.tip+'\',\''+t.ic+'\','+t.raf+',\''+t.mk+'\')" '+
      'style="padding:7px 12px;border:1px solid var(--brd);border-radius:10px;background:var(--bg);font-size:11px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:4px;font-family:Nunito">'+
        '<span>'+t.ic+'</span><span>'+t.tip+'</span>'+
      '</button>'
    ).join('')+
    '</div>'+
  '</div>'+
  // ── Mevcut ekmekler ──
  (liste.length===0?
    '<div class="cd" style="text-align:center;padding:24px;color:var(--txtL)">'+
      '<div style="font-size:48px;margin-bottom:8px">🪹</div>'+
      '<div style="font-size:13px;font-weight:700">Ekmeklik boş</div>'+
      '<div style="font-size:11px;margin-top:4px">Ekmek eklemek için + butonuna dokun</div>'+
    '</div>':
    '<div class="cd" style="padding:0;overflow:hidden">'+
      liste.map((e,i)=>{
        const tz=ekTazelik(e.dt,e.raf);
        const bayatMi=tz.pct<=0;
        return'<div style="padding:12px;border-bottom:1px solid var(--brd);display:flex;align-items:center;gap:10px;'+(bayatMi?'opacity:.55':'')+'">'+
          '<div style="font-size:28px;flex-shrink:0">'+e.ic+'</div>'+
          '<div style="flex:1;min-width:0">'+
            '<div style="font-size:13px;font-weight:700;display:flex;align-items:center;gap:6px">'+
              esc(e.tip)+
              (e.adet>1?'<span style="background:var(--primary);color:#fff;font-size:9px;padding:2px 7px;border-radius:8px;font-weight:800">x'+e.adet+'</span>':'')+
              '<span style="font-size:12px">'+tz.icon+'</span>'+
            '</div>'+
            '<div style="font-size:10px;color:var(--txtL);margin-top:2px">'+
              (e.dt?'Alındı: '+e.dt+' · ':'')+
              '<span style="color:'+tz.yazı+';font-weight:700">'+tz.etiket+'</span>'+
            '</div>'+
            // Taze bar
            '<div style="height:4px;background:var(--brd);border-radius:2px;margin-top:5px;overflow:hidden">'+
              '<div style="height:100%;width:'+tz.pct+'%;background:'+tz.renk+';border-radius:2px;transition:.3s"></div>'+
            '</div>'+
          '</div>'+
          '<div style="display:flex;flex-direction:column;gap:4px;flex-shrink:0">'+
            '<button onclick="ekAdet('+i+',-1)" style="width:30px;height:30px;border-radius:50%;border:1px solid var(--brd);background:var(--bg);font-size:16px;font-weight:700;cursor:pointer;display:flex;align-items:center;justify-content:center">−</button>'+
            '<button onclick="ekSil('+i+')" style="width:30px;height:30px;border-radius:50%;border:none;background:var(--dangerL);color:var(--danger);font-size:12px;cursor:pointer;display:flex;align-items:center;justify-content:center;font-weight:700">✕</button>'+
          '</div>'+
        '</div>'
      }).join('')+
    '</div>'
  )+
  // ── Bayat ekmekler uyarı ──
  (bayat.length?
    '<div style="background:var(--dangerL);border-radius:var(--r);padding:10px;margin-top:10px">'+
      '<div style="font-size:10px;font-weight:800;color:var(--danger);margin-bottom:6px">⚠️ BAYAT — ÇÖPE AT</div>'+
      bayat.map(e=>'<div style="font-size:11px;font-weight:700;display:flex;justify-content:space-between;align-items:center">'+
        '<span>'+e.ic+' '+esc(e.tip)+'</span>'+
        '<button onclick="ekSilBayatlar()" style="border:none;background:var(--danger);color:#fff;padding:3px 10px;border-radius:6px;font-size:10px;font-weight:700;cursor:pointer;font-family:Nunito">Temizle</button>'+
      '</div>').join('')+
    '</div>':''
  )
}

// Hızlı 1 adet ekle (bugünün tarihi)
function ekHizliEkle(tip,ic,raf,mk){
  if(!S.EK)S.EK=[];
  // Aynı tip varsa adet artır
  const mevcut=S.EK.find(e=>e.tip===tip&&ekTazelik(e.dt,e.raf).pct>0);
  if(mevcut){mevcut.adet=(mevcut.adet||1)+1;}
  else{S.EK.push({id:Date.now(),tip,ic,raf,mk,adet:1,dt:tISO()});}
  sv('EK');toast('🍞 '+tip+' eklendi!','succ',2000);rn();
}

