function svEkEkle(){
  const combo=document.getElementById('ek_tip').value.split('|');
  let tip=combo[0],ic=combo[1],raf=Number(combo[2]),mk=combo[3];
  // Özel ekmek türü
  if(tip==='__ozel__'){
    tip=document.getElementById('ek_ozel_nm').value.trim();
    if(!tip){toast('Ekmek adı gir!','warn');return;}
    ic='🍞';
    raf=Math.max(1,Number(document.getElementById('ek_ozel_raf').value)||7);
    // Özel türü listeye kalıcı ekle
    if(!EKMEK_TIPLER.find(t=>t.tip===tip)){
      EKMEK_TIPLER.splice(EKMEK_TIPLER.length-1,0,{tip,ic,raf,mk,not:'Özel tür'});
    }
  }
  const adet=Math.max(1,Number(document.getElementById('ek_adet_n').textContent)||1);
  const dt=document.getElementById('ek_dt').value||tISO();
  if(!S.EK)S.EK=[];
  S.EK.push({id:Date.now(),tip,ic,raf,mk,adet,dt});
  sv('EK');document.querySelector('.mo').remove();
  toast('🍞 '+tip+' eklendi!','succ');rn();
}

// Adet azalt / artır
function ekAdet(idx,delta){
  if(!S.EK||!S.EK[idx])return;
  S.EK[idx].adet=Math.max(0,(S.EK[idx].adet||1)+delta);
  if(S.EK[idx].adet===0)S.EK.splice(idx,1);
  sv('EK');rn();
}

// Ekmek sil
function ekSil(idx){
  if(!S.EK)return;
  S.EK.splice(idx,1);sv('EK');rn();
}

// Bayatları temizle
function ekSilBayatlar(){
  if(!S.EK)return;
  S.EK=S.EK.filter(e=>ekTazelik(e.dt,e.raf).pct>0);
  sv('EK');toast('🗑 Bayat ekmekler temizlendi','info');rn();
}

